$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_5ee406d769ac3887713d3308a0d01601'] = 'Adja meg, hány napig maradjanak meg a nyers PrestaShop látogatói statisztikák. Példa: 60 azt jelenti, hogy a modul az utolsó 60 napot megtartja, a régebbi rekordokat pedig törli a ps_connections, ps_connections_source és ps_connections_page táblákból. Ne állítsa 1-re, hacsak nem biztos benne, hogy nincs szüksége friss látogatói statisztikákra.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_1300769d8d72fc8218b40772f1c25efc'] = 'Kötegméret';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_631c4c75cb36e0fcee3da42ef67e730e'] = 'Egy kötegben feldolgozott kapcsolatok maximális száma.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_acbc6e359c79ace4ef9b5398148c13e2'] = 'Adja meg, hány fő kapcsolati rekord dolgozható fel egy belső kötegben. A kisebb érték biztonságosabb gyenge tárhelyen, de több cron futást igényel. A nagyobb érték gyorsabban tisztít, de tovább tarthat adatbázis-zárakat. Ajánlott kezdőérték: 1000–5000; csak futási idő tesztelése után növelje.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_2806977593fb4c23003cc11306b135d1'] = 'Maximális kötegek futásonként';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d31a094a19379b58b63b51ef0f9d9362'] = 'Korlátozza, mennyi munkát végezhet egy cron futás.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_e221a5a91ea62a43adc5bb15614eb578'] = 'Adja meg, hány köteg futhat egy cron futás alatt. A futásonként törölhető fő kapcsolati rekordok száma nagyjából Kötegméret szorozva Maximális kötegek futásonként. Példa: 5000 és 10 legfeljebb kb. 50000 rekordot jelent egy cron futásban. Csökkentse, ha az áruház lassul tisztítás közben.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a1a47524ffa9c839887703df1fbe70a3'] = 'ps_layered_filter_block ürítése';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_924684322fe68e56ef9205e7f480f598'] = 'Kiüríti a faceted/layered keresési blokk gyorsítótárát TRUNCATE TABLE paranccsal. A MySQL/MariaDB üresen hozza létre újra a táblát.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_92a6452eb793565a92aa28e5f9a3f2e5'] = 'Csak akkor engedélyezze, ha a ps_layered_filter_block túl nagyra nő vagy elavult faceted keresési cache-t tartalmaz. Ez nem töröl termékeket, kategóriákat vagy layered árindexet. Tisztítás után a PrestaShop vagy a faceted kereső modul szükség szerint újraépítheti a cache-t.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_bf45506cce2494894a9df6ff4bdf83ae'] = 'Forgalmi forrás statisztikák összesítése törlés előtt';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d7e1a0c7e7973ebcde37aa659525105d'] = 'Napi összesített forgalmi forrás statisztikákat ment a nyers sorok törlése előtt.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ae729759e10d7a626a8622321932a1f4'] = 'Engedélyezve a modul kis napi összefoglalót ment a nyers PrestaShop statisztikák eltávolítása előtt. Megőrzi a látogatások, oldalmegtekintések, forrásdomain és UTM értékek számát. Nem tárol IP-címeket, teljes referrer URL-eket vagy user-agent karakterláncokat. Kapcsolja ki, ha csak törölni szeretne és nincs szüksége előzmény összesítésekre.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ce2b282d224153cccd645f28504ab4e2'] = 'Összesített statisztikák megőrzési napjai';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_c3b4d14f7bff29c221039e891918f2dd'] = 'Meddig maradjon meg a kis napi összesítő tábla.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a97a6a6ab09f48206a543fdc7321bb60'] = 'Adja meg, hány napig maradjanak a forgalmi forrás összesítések a modul táblájában. Példa: 730 körülbelül két év napi összesítést tart meg. Ez csak a ps_jooim_dbcleaner_traffic_daily táblát érinti, nem az eredeti PrestaShop statisztikai táblákat.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_4d4c70d739ad72835a8b62a81e07c611'] = 'Elavult zárolás időkorlátja másodpercben';
